var b="url",c="应付调整单.html",d="generationDate",e=new Date(1781585079059.85),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="0599f9a769154fcd924c7ba332585784",v="type",w="Axure:Page",x="应付调整单",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="5e41a5e1f7904b3e9ff0e6bfe72a27e8",E="label",F="删除",G="说明",H="<p><span>1.校验是否存在勾选单据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.勾选为空：Toast提示“请勾选须要删除的单据”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.存在勾选：通过校验</span></p><p><span>2.校验勾选的单据状态是否均为“待提交”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.非待提交：Toast提示“仅可对'待提交'的单据进行删除”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.待提交：二次弹窗确认后执行删除</span></p>",I="2",J="8adc458b220745e590034ac552c98aab",K="<p><span>单号规则：YFJS+2位年份+2位月份+3位流水</span></p>",L="3",M="e82c3ba551d544cfad316f39a759214b",N="调整类型",O="<p><span>释义</span></p><p><span>1.直接调整：针对应付对象的整体应付金额调整</span></p><p><span>2.对单调整：针对应付关联(物料结算单/XX结算单)的调整</span></p><p><span>3.结清调整：付款申请明细行进行通过[付款单]进行</span><span style=\"text-decoration:underline ;\">强制结清</span><span>时，将[对单付款]的'剩余差额'作为当前的“调整金额”</span></p>",P="4",Q="ac6384f0057e4ed1ab5c23c2d30d8772",R="调整应付0",S="<p><span>1.展示方式：居右；数值</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">跟随[系统配置&gt;&gt;采购配置：通用设置]中配置的&quot;金额补位&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.金额补位==否：无须补位</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.金额补位==是：数值补'0'至3位小数</span></p>",T="5",U="f0d583f0b66b4c37b1deab8650e9d015",V="更新人",W="<p><span>创建时初始为操作人；后续编辑后保存将同步操作人为更新人</span></p>",X="6",Y="ca79cda1ab0b46d18098fe44aa9dd526",Z="(下拉列表)",ba="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.可选项</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.供应商(默认选中)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.【暂不开发】外发工厂</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.每切换'对象类型'时，将'调整对象'的选中项清空</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.无法置空</span></p>",bb="7",bc="fdc5b156befe4c1ea6d193be2c0dfc3b",bd="<p><span>1.数据源：跟随选中的'对象类型'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.供应商：[基础数据&gt;&gt;供应商管理]中“启用”的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.支持对'供应商名称'的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.【暂不开发】外发工厂：[基础数据&gt;&gt;外发工厂]中“启用”的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1.支持对'外发工厂名称'的模糊搜索</span></p><p><span>2.每切换'对象类型'时，当前选中项清空</span></p>",be="8",bf="0309bf4747024f9e941e44edfad2a97e",bg="确认",bh="<p><span>1.校验'调整对象'非空，否则Toast提示：请选择调整对象</span></p><p><span>2.通过校验：带值跳转至调整单新增页</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将选中的'对象类型'和'调整对象'代入</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.调整类型：固定为'对单调整'</span></p>",bi="style",bj="baseStyle",bk="627587b6038d43cca051c114ac41ad32",bl="pageAlignment",bm="center",bn="fill",bo="fillType",bp="solid",bq="color",br=0xFFFFFFFF,bs="image",bt="imageAlignment",bu="near",bv="imageRepeat",bw="auto",bx="favicon",by="sketchFactor",bz="0",bA="colorStyle",bB="appliedColor",bC="fontName",bD="Applied Font",bE="borderWidth",bF="borderVisibility",bG="borderFill",bH=0xFF797979,bI="cornerRadius",bJ="cornerVisibility",bK="outerShadow",bL="on",bM=false,bN="offsetX",bO=5,bP="offsetY",bQ="blurRadius",bR="spread",bS="r",bT=0,bU="g",bV="b",bW="a",bX=0.349019607843137,bY="adaptiveStyles",bZ="interactionMap",ca="diagram",cb="objects",cc="id",cd="2874aa50934e41b6a76777be9d3d0686",ce="friendlyType",cf="顶部-1600",cg="referenceDiagramObject",ch="styleType",ci="visible",cj=true,ck=1600,cl=890,cm="imageOverrides",cn="masterId",co="17274bcf1e104e0881fe339074a81b64",cp="b9053176b635443984d3fd8158a6afb7",cq